93:     /**
94:      * Create a new record accumulator
95:      *
96:      * @param logContext The log context used for logging
97:      * @param batchSize The size to use when allocating {@link MemoryRecords} instances
98:      * @param compression The compression codec for the records
99:      * @param lingerMs An artificial delay time to add before declaring a records instance that isn't full ready for
100:      *        sending. This allows time for more records to arrive. Setting a non-zero lingerMs will trade off some
101:      *        latency for potentially better throughput due to more batching (and hence fewer, larger requests).
102:      * @param retryBackoffMs An artificial delay time to retry the produce request upon receiving an error. This avoids
103:      *        exhausting all retries in a short period of time.
104:      * @param retryBackoffMaxMs The upper bound of the retry backoff time.
105:      * @param deliveryTimeoutMs An upper bound on the time to report success or failure on record delivery
106:      * @param partitionerConfig Partitioner config
107:      * @param metrics The metrics
108:      * @param metricGrpName The metric group name
109:      * @param time The time instance to use
110:      * @param transactionManager The shared transaction state object which tracks producer IDs, epochs, and sequence
111:      *                           numbers per partition.
112:      * @param bufferPool The buffer pool
113:      */
114:     public RecordAccumulator(LogContext logContext,
115:                              int batchSize,
116:                              Compression compression,
117:                              int lingerMs,
118:                              long retryBackoffMs,
119:                              long retryBackoffMaxMs,
120:                              int deliveryTimeoutMs,
121:                              PartitionerConfig partitionerConfig,
122:                              Metrics metrics,
123:                              String metricGrpName,
124:                              Time time,
125:                              TransactionManager transactionManager,
126:                              BufferPool bufferPool) {
127:         this.logContext = logContext;
128:         this.log = logContext.logger(RecordAccumulator.class);
129:         this.closed = false;
130:         this.flushesInProgress = new AtomicInteger(0);
131:         this.appendsInProgress = new AtomicInteger(0);
132:         this.batchSize = batchSize;
133:         this.compression = compression;
134:         this.lingerMs = lingerMs;
135:         this.retryBackoff = new ExponentialBackoff(retryBackoffMs,
136:                 CommonClientConfigs.RETRY_BACKOFF_EXP_BASE,
137:                 retryBackoffMaxMs,
138:                 CommonClientConfigs.RETRY_BACKOFF_JITTER);
139:         this.deliveryTimeoutMs = deliveryTimeoutMs;
140:         this.enableAdaptivePartitioning = partitionerConfig.enableAdaptivePartitioning;
141:         this.partitionAvailabilityTimeoutMs = partitionerConfig.partitionAvailabilityTimeoutMs;
142:         this.free = bufferPool;
143:         this.incomplete = new IncompleteBatches();
144:         this.muted = new HashSet<>();
145:         this.time = time;
146:         nodesDrainIndex = new HashMap<>();
147:         this.transactionManager = transactionManager;
148:         registerMetrics(metrics, metricGrpName);
149:     }
